import{_ as e,o as t,c as i,a as n}from"./app.d194702d.js";var a="/aktivitaeten/BDM-2026-05/00_05-2026.jpg",r="/aktivitaeten/BDM-2026-05/01_05-2026.jpg",s="/aktivitaeten/BDM-2026-05/02_05-2026.jpg",d="/aktivitaeten/BDM-2026-05/03_05-2026.jpg",l="/aktivitaeten/BDM-2026-05/04_05-2026.jpg",m="/aktivitaeten/BDM-2026-05/05_05-2026.jpg",g="/aktivitaeten/BDM-2026-05/06_05-2026.jpg",o="/aktivitaeten/BDM-2026-05/07_05-2026.jpg",p="/aktivitaeten/BDM-2026-05/08_05-2026.jpg",u="/aktivitaeten/BDM-2026-05/09_05-2026.jpg",c="/aktivitaeten/BDM-2026-05/10_05-2026.jpg",h="/aktivitaeten/BDM-2026-05/11_05-2026.jpg",_="/aktivitaeten/BDM-2026-05/12_05-2026.jpg",v="/aktivitaeten/BDM-2026-05/13_05-2026.jpg",B="/aktivitaeten/BDM-2026-05/14_05-2026.jpg",k="/aktivitaeten/BDM-2026-05/15_05-2026.jpg",M="/aktivitaeten/BDM-2026-05/16_05-2026.jpg",D="/aktivitaeten/BDM-2026-05/17_05-2026.jpg",b="/aktivitaeten/BDM-2026-05/18_05-2026.jpg",f="/aktivitaeten/BDM-2026-05/19_05-2026.jpg",w="/aktivitaeten/BDM-2026-05/20_05-2026.jpg",A="/aktivitaeten/BDM-2026-05/21_05-2026.jpg",j="/aktivitaeten/BDM-2026-05/22_05-2026.jpg",S="/aktivitaeten/BDM-2026-05/23_05-2026.jpg",z="/aktivitaeten/BDM-2026-05/24_05-2026.jpg",E="/aktivitaeten/BDM-2026-05/25_05-2026.jpg",T="/aktivitaeten/BDM-2026-05/26_05-2026.jpg",O="/aktivitaeten/BDM-2026-05/27_05-2026.jpg",H="/aktivitaeten/BDM-2026-05/28_05-2026.jpg",P="/aktivitaeten/BDM-2026-05/29_05-2026.jpg",W="/aktivitaeten/BDM-2026-05/30_05-2026.jpg",C="/aktivitaeten/BDM-2026-05/31_05-2026.jpg",F="/aktivitaeten/BDM-2026-05/32_05-2026.jpg",L="/aktivitaeten/BDM-2026-05/33_05-2026.jpg",N="/aktivitaeten/BDM-2026-05/34_05-2026.jpg",R="/aktivitaeten/BDM-2026-05/35_05-2026.jpg",Q="/aktivitaeten/BDM-2026-05/36_05-2026.jpg",G="/aktivitaeten/BDM-2026-05/37_05-2026.jpg",K="/aktivitaeten/BDM-2026-05/38_05-2026.jpg",U="/aktivitaeten/BDM-2026-05/39_05-2026.jpg",q="/aktivitaeten/BDM-2026-05/40_05-2026.jpg",X="/aktivitaeten/BDM-2026-05/41_05-2026.jpg",V="/aktivitaeten/BDM-2026-05/42_05-2026.jpg",I="/aktivitaeten/BDM-2026-05/43_05-2026.jpg",Z="/aktivitaeten/BDM-2026-05/44_05-2026.jpg",x="/aktivitaeten/BDM-2026-05/45_05-2026.jpg",J="/aktivitaeten/BDM-2026-05/46_05-2026.jpg",Y="/aktivitaeten/BDM-2026-05/47_05-2026.jpg",y="/aktivitaeten/BDM-2026-05/48_05-2026.jpg",$="/aktivitaeten/BDM-2026-05/49_05-2026.jpg",ee="/aktivitaeten/BDM-2026-05/50_05-2026.jpg",te="/aktivitaeten/BDM-2026-05/51_05-2026.jpg",ie="/aktivitaeten/BDM-2026-05/52_05-2026.jpg",ne="/aktivitaeten/BDM-2026-05/53_05-2026.jpg",ae="/aktivitaeten/BDM-2026-05/54_05-2026.jpg",re="/aktivitaeten/BDM-2026-05/55_05-2026.jpg",se="/aktivitaeten/BDM-2026-05/56_05-2026.jpg",de="/aktivitaeten/BDM-2026-05/57_05-2026.jpg",le="/aktivitaeten/BDM-2026-05/58_05-2026.jpg",me="/aktivitaeten/BDM-2026-05/59_05-2026.jpg",ge="/aktivitaeten/BDM-2026-05/60_05-2026.jpg",oe="/aktivitaeten/BDM-2026-05/61_05-2026.jpg",pe="/aktivitaeten/BDM-2026-05/62_05-2026.jpg",ue="/aktivitaeten/BDM-2026-05/63_05-2026.jpg",ce="/aktivitaeten/BDM-2026-05/64_05-2026.jpg",he="/aktivitaeten/BDM-2026-05/65_05-2026.jpg",_e="/aktivitaeten/BDM-2026-05/66_05-2026.jpg",ve="/aktivitaeten/BDM-2026-05/67_05-2026.jpg",Be="/aktivitaeten/BDM-2026-05/68_05-2026.jpg",ke="/aktivitaeten/BDM-2026-05/69_05-2026.jpg",Me="/aktivitaeten/BDM-2026-05/70_05-2026.jpg",De="/aktivitaeten/BDM-2026-05/71_05-2026.jpg",be="/aktivitaeten/BDM-2026-05/72_05-2026.jpg",fe="/aktivitaeten/BDM-2026-05/73_05-2026.jpg",we="/aktivitaeten/BDM-2026-05/74_05-2026.jpg",Ae="/aktivitaeten/BDM-2026-05/75_05-2026.jpg",je="/aktivitaeten/BDM-2026-05/76_05-2026.jpg",Se="/aktivitaeten/BDM-2026-05/77_05-2026.jpg",ze="/aktivitaeten/BDM-2026-05/78_05-2026.jpg",Ee="/aktivitaeten/BDM-2026-05/79_05-2026.jpg",Te="/aktivitaeten/BDM-2026-05/80_05-2026.jpg",Oe="/aktivitaeten/BDM-2026-05/81_05-2026.jpg",He="/aktivitaeten/BDM-2026-05/82_05-2026.jpg",Pe="/aktivitaeten/BDM-2026-05/83_05-2026.jpg",We="/aktivitaeten/BDM-2026-05/84_05-2026.jpg",Ce="/aktivitaeten/BDM-2026-05/85_05-2026.jpg",Fe="/aktivitaeten/BDM-2026-05/86_05-2026.jpg",Le="/aktivitaeten/BDM-2026-05/87_05-2026.jpg",Ne="/aktivitaeten/BDM-2026-05/88_05-2026.jpg",Re="/aktivitaeten/BDM-2026-05/89_05-2026.jpg";const Qe={},Ge=n('<h1 id="bilder-des-monats-mai-2026" tabindex="-1"><a class="header-anchor" href="#bilder-des-monats-mai-2026" aria-hidden="true">#</a> Bilder des Monats Mai 2026</h1><p>Am 1. Mai hat es mich, Harm DK4HAA, in den Hamburger Osten gezogen und gemeinsam mit Tobias (DC1TC) und Familie ging es nach DE-0537, Naturschutzgebiet H\xF6ltigbaum. Wir waren prim\xE4r auf 40m unterwegs und haben gezielt Schloss- und Burgen-Stationen gehuntet, die am Burgentag on air waren. Bei bestem Wetter und rund 23 Grad hat sich der schwarze Block in der Sonne schnell aufgel\xF6st. Trotz starkem QSB 40m und einem OTHR auf 20m haben wir uns am Ende \xFCber eine Vielzahl an QSOs im Log gefreut.</p><p><img src="'+a+'" alt="Bilder des Monats"><img src="'+r+'" alt="Bilder des Monats"></p><p>Nach viel zu langer Zeit war ich (DC1TC) auch mal wieder in nem Park unterwegs. Es war eine sehr gem\xFCtliche Nachmittagsaktivierung zusammen mit Harm (DK4HAA) in meinem neuen \u201CHauspark\u201D DE-0537.</p><p><img src="'+s+'" alt="Bilder des Monats"><img src="'+d+'" alt="Bilder des Monats"></p><p><img src="'+l+'" alt="Bilder des Monats"></p><p>Ein Tagesausflug nach Bleckede brachte mich (DL2XU) dazu, neben der erfolgreichen Aktivierung von 4 Parks on the Air Referenzen, diese sehr sch\xF6ne Kleinstadt zu erkunden. Der Spot ist toll da er am Elberadweg liegt und man dort direkt daneben auf dem Deich aufbauen kann. Es gab einige interessierte Radfahrer mit denen ich ins Gespr\xE4ch kam. Die Bedingungen waren nicht die Besten und auf den B\xE4ndern &gt;14MHz kamen leider keine QSOs zustande. Trotzdem hatte ich viel Spa\xDF und kommte im Sonnenschein bei 26\xB0C und angenehmem Wind 44 Verbindungen in CW und SSB ins Logbook eintragen. Sch\xF6ne Stadt, sch\xF6ner Spot, 4 Referenzen. Klare Empfehlung.</p><p><img src="'+m+'" alt="Bilder des Monats"><img src="'+g+'" alt="Bilder des Monats"><img src="'+o+'" alt="Bilder des Monats"><img src="'+p+'" alt="Bilder des Monats"><img src="'+u+'" alt="Bilder des Monats"><img src="'+c+'" alt="Bilder des Monats"><img src="'+h+'" alt="Bilder des Monats"><img src="'+_+'" alt="Bilder des Monats"></p><p>Heute Finkenwerder R\xFCschpark, 7 Stationen inclusive der Cap san Diego (DL0MFH)</p><p><img src="'+v+'" alt="Bilder des Monats"></p><p>DB6NL - Bei der Westfalen S\xFCd Aktivit\xE4t haben DB4LL und ich eine Parabolantenne auf 23cm getestet. ODX waren ca. 70 km bis nach JO31QX mit 2W und theoretische 20dB von der Antenne. Neben den \xFCblichen QSOs auf 2m und 70cm kamen so auch 4 QSOs auf 23cm ins Log.</p><p><img src="'+B+'" alt="Bilder des Monats"><img src="'+k+'" alt="Bilder des Monats"><img src="'+M+'" alt="Bilder des Monats"></p><p>DA6MAX - Wanderh\xFCtte am Ernstberg, Hessen DE-0042 Hoher Vogelsberg Nature Park - Aktivierung nahe dem Hoherodskopf in einer fast schon luxuri\xF6sen H\xFCtte</p><p><img src="'+D+'" alt="Bilder des Monats"><img src="'+b+'" alt="Bilder des Monats"><img src="'+f+'" alt="Bilder des Monats"></p><p>Am 13.05.2026 hat DB7GKA seine abendliche Freizeit genutzt, um den Perlacher Forst mit der POTA-Referenz DE-1152 an der Waldlichtung beim Hirschbrunnen in CW zu aktivieren.</p><p><img src="'+w+'" alt="Bilder des Monats"><img src="'+A+'" alt="Bilder des Monats"><img src="'+j+'" alt="Bilder des Monats"><img src="'+S+'" alt="Bilder des Monats"><img src="'+z+'" alt="Bilder des Monats"><img src="'+E+'" alt="Bilder des Monats"><img src="'+T+'" alt="Bilder des Monats"></p><p>POTA-Aktivierung NO-2628 \u2013 Nordkapp-fjellet og Hornvika Flora and Fauna Reserve Am 15. Mai 2026 aktivierte ich als LA/DA6MAX eines der spektakul\xE4rsten POTA-Gebiete Europas: das Nordkapp auf 71\xB0 Nord. Die karge, schneegefleckte Hochebene am Ende der Welt bot nicht nur eine atemberaubende Kulisse, sondern auch \xFCberraschend gute Ausbreitungsbedingungen \u2013 trotz Wind und arktischen Temperaturen. Mit einem einfachen Vertikalstrahler, aufgestellt auf dem Schotterparkplatz direkt neben dem ber\xFChmten Globus-Monument, gelangen mir in 1h 18 Minuten 20 QSOs auf 20m und 15m (SSB &amp; FT8) in 11 DXCC-Entit\xE4ten \u2013 von Spanien bis Zypern, von Schweden bis Griechenland. Die Aktivierung f\xFChlte sich wie eine kleine DXpedition an \u2013 der Aufwand, bis ans n\xF6rdlichste Ende Europas zu fahren, hat sich mehr als gelohnt.</p><p><img src="'+O+'" alt="Bilder des Monats"><img src="'+H+'" alt="Bilder des Monats"><img src="'+P+'" alt="Bilder des Monats"><img src="'+W+'" alt="Bilder des Monats"><img src="'+C+'" alt="Bilder des Monats"><img src="'+F+'" alt="Bilder des Monats"><img src="'+L+'" alt="Bilder des Monats"></p><p>DA6XJ aktivierung von DE-0042 mal den neuen buddihex getestet und f\xFCr SEHR gut befunden.</p><p><img src="'+N+'" alt="Bilder des Monats"><img src="'+R+'" alt="Bilder des Monats"><img src="'+Q+'" alt="Bilder des Monats"></p><p>DB7GKA am 15.05.2026 beim Perlacher Mugl im Perlacher Forst (POTA-Referenz DE-1152). Die ersten sechs QSOs kamen nach dem initialen CQ-Ruf innerhalb der ersten Minuten in CW ins Log. Dann haben leider mehrere kurze Platzregenschauer dem CQ-Run ein schnelles Ende bereitet. Zwischen den kurzen Regeng\xFCssen wurde die Aktivierung als SOTA- und POTA-Chaser noch erfolgreich in CW zu Ende gebracht, um dann z\xFCgig abzubauen und nach Hause zu radeln.</p><p><img src="'+G+'" alt="Bilder des Monats"><img src="'+K+'" alt="Bilder des Monats"><img src="'+U+'" alt="Bilder des Monats"><img src="'+q+'" alt="Bilder des Monats"></p><p>DL3BOB Aktivierung DE-0661 &amp; DE-0662 Pfrunger Ried und Seen bei Illmensee am Bannwald-Turm</p><p><img src="'+X+'" alt="Bilder des Monats"><img src="'+V+'" alt="Bilder des Monats"></p><p>DA6MAX - POTA-Erstaktivierung NO-2005 \u2013 Sp\xE5kenes\xF8ra Nature Reserve</p><p>Am 16. Mai 2026 durfte ich als LA/DA6MAX das Sp\xE5kenes\xF8ra Nature Reserve in Nordnorwegen als Erstaktivierender in die POTA-Datenbank eintragen. Das Reservat liegt an der K\xFCste der Troms-Region, eingebettet zwischen spiegelglattem Fjordwasser und schneebedeckten Gipfeln \u2013 eine Ruhe und Urspr\xFCnglichkeit, die man so schnell nicht vergisst. Die Antenne wurde direkt am Felsstrand aufgebaut, das Wetter spielte perfekt mit. Funkseitig war es durch einen koronalen Masseauswurf in der Nacht zuvor eine Herausforderung, dennoch gelangen mir 13 QSOs in 10 DXCC-Entit\xE4ten auf 20m \u2013 von Polen und Belgien bis Rum\xE4nien und der Ukraine. Ein w\xFCrdiger Abschluss eines epischen Norwegen-Trips.</p><p><img src="'+I+'" alt="Bilder des Monats"><img src="'+Z+'" alt="Bilder des Monats"><img src="'+x+'" alt="Bilder des Monats"><img src="'+J+'" alt="Bilder des Monats"><img src="'+Y+'" alt="Bilder des Monats"></p><p>Heute habe ich, DG4HZ, w\xE4hrend eines Kurzurlaubes in St. Peter Ording morgens um 6:30 Uhr Ortszeiten eine kurze Aktivierung des Nationalparks Schleswig Holsteinische Wattenmeer DE-0109 auf 40 Meter in FT 8 durchgef\xFChrt. In 1 Stunde kamen trotz der fr\xFChen Uhrzeit 18 QSOs ins Log, anschlie\xDFend lockte dann das Fr\xFChst\xFCck ins Hotel zur\xFCck.</p><p><img src="'+y+'" alt="Bilder des Monats"><img src="'+$+'" alt="Bilder des Monats"></p><p>DF9HC bei perfektem Sommerwetter mit einer sehr erfolgreichen Aktivierung am Strand. Die meisten QSOs in CW auf 3 B\xE4ndern und trotz QSB seit langem mal wieder etwas DX dabei gewesen.</p><p><img src="'+ee+'" alt="Bilder des Monats"><img src="'+te+'" alt="Bilder des Monats"><img src="'+ie+'" alt="Bilder des Monats"></p><p>Am 24.05. haben Holger (13-OT-4242, die Erdbeere) und ich, Harm (DK4HAA) den Duvenstedter Brook unsicher gemacht und neben einer POTA-Aktivierung im Amateurfunk auch CB-Funk betrieben und einige QSOs ins Log bekommen. Trotz M\xFCcken- und Raupen-Plage haben wir \xFCber zwei Stunden Betrieb gemacht. \u{1F4AA}</p><p><img src="'+ne+'" alt="Bilder des Monats"><img src="'+ae+'" alt="Bilder des Monats"><img src="'+re+'" alt="Bilder des Monats"><img src="'+se+'" alt="Bilder des Monats"><img src="'+de+'" alt="Bilder des Monats"><img src="'+le+'" alt="Bilder des Monats"><img src="'+me+'" alt="Bilder des Monats"><img src="'+ge+'" alt="Bilder des Monats"></p><p><img src="'+oe+'" alt="Bilder des Monats"></p><p>I/DB7GKA bei der fr\xFChmorgendlichen und vorfr\xFChst\xFCcklichen Urlaubsaktivierung des Naturschutzgebiets &quot;Laguna di Caorle - Foce del Tagliamento Natura 2000&quot; (IT-1515) in CW bei herrlich warmen 20 Grad Celsius und bew\xF6lkten Himmel. Nach anf\xE4nglichen m\xFCdigkeitsbedingten Leseschwierigkeiten der CW-Signale, lief die Aktivierung dank meiner sehr geduldigen POTA-Chaser immer geschmeidiger ab.</p><p><img src="'+pe+'" alt="Bilder des Monats"><img src="'+ue+'" alt="Bilder des Monats"><img src="'+ce+'" alt="Bilder des Monats"></p><p>Der UKW-Teil des Hamburg-Contest war die perfekte Gelegenheit f\xFCr DL6PL, einen seiner Lieblingsspots anzufahren. Bei bestem Wetter ging es in die Hahnheide (POTA-Referenz DE-0957) nord\xF6stlich von Hamburg. Mit einem Stativ, einer Yagi von Arrow Antenna und einem FT-817ND bewaffnet war der Aussichtsturm &quot;Langer Otto&quot; das Ziel: Ein etwa 27 m hoher Holzturm, der auf einer 99 m hohen Erhebung steht. F\xFCr norddeutsche Verh\xE4ltnisse also recht hoch. Auf 2 m gingen ein QSO in CW und 21 SSB-Kontakte ins Log, auf 70 cm waren es 14 SSB-Kontakte. Die Aktivierung war also locker gelungen und mit Gl\xFCck k\xF6nnte das sogar ein ansehnliches Ergebnis im Contest werden. Nat\xFCrlich konzentrieren sich die Kontakte auf Hamburg und das Umland, auf 2 m ging es sogar nach NRW, die nieders\xE4chsische Nordseek\xFCste, an die deutsch-d\xE4nische Grenze und in den S\xFCden Mecklenburg-Vorpommerns. Es bleibt die Erkenntnis, dass UKW leider v\xF6llig untersch\xE4tzt wird und mehr Aktivit\xE4t auch au\xDFerhalb vom Contest-Betrieb w\xFCnschenswert w\xE4re. Vielleicht wird das ja im Sonnenfleckenminimum mit vielen neuen N-Lizensierten was.</p><p><img src="'+he+'" alt="Bilder des Monats"><img src="'+_e+'" alt="Bilder des Monats"><img src="'+ve+'" alt="Bilder des Monats"></p><p>Schnelle Aktivierung von DE-0021 durch DB4SCW (als DL\xD8LOL) am Pfingstmontag. FT857D Portabelrucksack, PAC-12 Antenne, 100W SSB. 41 QSOs auf 40m + 20m, davon \xFCberraschenderweise 4 &quot;innerdeutsch&quot; auf 20m per Raumwelle, was aus meinem Heimat-QTH-Bereich nur \xE4u\xDFerst selten gelingt.</p><p><img src="'+Be+'" alt="Bilder des Monats"><img src="'+ke+'" alt="Bilder des Monats"></p><p>DO7EC am Vogelbrunnen im Naturpark M\xFCnden (DE-0060) am Pfingstmontag. Ein k\xFChles, lauschiges Pl\xE4tzchen! Meinen \xFCberhaupt ersten Aktivierungsversuch habe ich, Martin, nach 1 Stunde und 9 QSOs wegen der vielen M\xFCcken beendet, allerdings im guten Glauben ich h\xE4tte 10 QSOs geschafft \u{1F642} War spannend und hat super viel Spass gemacht! 15m FT8, Xiegu G90 mit DeltaLoop Antenne</p><p><img src="'+Me+'" alt="Bilder des Monats"><img src="'+De+'" alt="Bilder des Monats"><img src="'+be+'" alt="Bilder des Monats"><img src="'+fe+'" alt="Bilder des Monats"></p><p>DL7DL</p><p><img src="'+we+'" alt="Bilder des Monats"><img src="'+Ae+'" alt="Bilder des Monats"><img src="'+je+'" alt="Bilder des Monats"><img src="'+Se+'" alt="Bilder des Monats"></p><p>DL9CE auf dem T\xF6nsberg in Oerlinghausen. Bei bestem Fr\xFChsommer-Wetter gab es zun\xE4chst eine POTA-Aktivierung von DE-1014, DE-0834 und DE-0072 auf dem 40m-Band, sp\xE4ter kamen noch eine Handvoll FT8-Verbindungen auf 2m zustande. Als Abschluss folgte dann noch die Teilnahme an der w\xF6chentlichen SSB-Funkrunde auf dem 2m-Band.</p><p><img src="'+ze+'" alt="Bilder des Monats"><img src="'+Ee+'" alt="Bilder des Monats"></p><p>Ich (Uz, DF5WC) versuche gerne, Portabel Aktivit\xE4ten nebenher zu planen, wenn ich sowieso mit dem Auto unterwegs bin. Am 27. Mai bot sich eine solche Gelegenheit. Ich hatte versprochen, meine Frau von einem Aufenthalt im s\xFCdlichen Schwarzwald abzuholen. Der Weg dorthin f\xFChrt von uns aus (wenn man nicht gerade Autobahn f\xE4hrt) \xFCber die Schw\xE4bische Alb - und dort warten einige &quot;Tausender&quot; geduldig auf eine SOTA Aktivierung. Meine Wahl fiel auf den Plettenberg (DM/BW-046), der nur wenige Kilometer Umweg erfordert. Nebenher fallen dort noch die POTA Parks DE-0929 (HW1) und DE-0948 (HW3) an.</p><p>Die konkrete Planung am Tag vorher: Ankunft bei meiner Frau: 9:30 Uhr. Fahrtzeit gesamt 1:30 Stunden, Auf- und Abstieg zum Plettenberg je 15 Minuten, Zeit f\xFCr die Aktivierung ca. 60 Minuten plus 15 Minuten f\xFCr Auf- und Abbau. Ergibt eine Abfahrtszeit von 6:00 Uhr, d.h. Weckzeit 5:00 Uhr. Was auch gut gepasst hat, weil f\xFCr den Tag Temperaturen von 30\xB0 angesagt waren - da freut man sich, morgens noch ohne \xFCberm\xE4\xDFige Schwei\xDFausbr\xFCche im Schatten sitzen zu k\xF6nnen.</p><p>Tats\xE4chlich kam ich kurz nach 6 Uhr los und war ca. 6:50 Uhr am Parkplatz unterhalb des Plettenbergs. Trotz der fr\xFChen Stunde war die Seilbahn schon in Betrieb. Der Aufstieg war zwar steil, aber sch\xF6n und nicht sonderlich schwierig. Generell war der Morgen wundersch\xF6n mit einer &quot;Idealtemperatur&quot; von anfangs knapp 20\xB0. Gegen 7:05 war ich auf dem Gipfel, den ich von meiner Wanderung auf dem HW1 voriges Jahr schon kannte. Nach den obligatorischen Gipfelfotos wurde aufgebaut: FT-857 mit Drau\xDFenfunker Vertical und 12Ah Eremit Akku. Den FT-857 hatte ich im letzten Moment noch statt des eigentlichen geplanten QRP Ger\xE4ts eingepackt, weil ich teilweise schlechte Erfahrungen mit sehr fr\xFChen Aktivierungen in der Woche gemacht habe. Wegen der limitierten Zeit wollte ich kein Risiko eingehen.</p><p>Gegen 7:15 Uhr war ich betriebsbereit, habe mich gespottet und angefangen, auf 20m in CW CQ zu rufen. Dann: Nichts. Nach 7 Minuten erfolglosen Rufens antwortet mir VK4FW, dann wieder: nichts. Ich wechsle auf 40m und dort l\xE4uft es dann rund. Innerhalb von 30 Minuten kommen ca. 30 QSOs ins Log. Besonders gefreut hat mich ein QSO mit Ben, DJ0YI, der neuer Besitzer meines KX1 ist. Als das Pileup nachl\xE4\xDFt grase ich noch 20 und 30m ab wo ich weitere 9 QSOs machen kann, wenn auch mit mehr &quot;Luft&quot; dazwischen. Leider waren weder andere SOTA Aktivierer noch Drau\xDFenfunker dabei. Gegen 8:20 Uhr baue ich zufrieden ab und mache mich an den Abstieg. Meine Frau erreiche ich gegen 9:20 Uhr.</p><p>Insgesamt war es eine sehr sch\xF6ne Aktivierung. Der s\xFCdliche Teil der Schw\xE4bischen Alb ist wunderh\xFCbsch, die Temperatur war angenehm, der zeitliche Ablauf perfekt, und ein kleines Pileup abarbeiten zu k\xF6nnen macht auch immer wieder Spa\xDF. Der Aufwand f\xFCr ein solches &quot;Abenteuer&quot; ist wirklich minimal. Pr\xE4dikat: Empfehlenswert!</p><p><img src="'+Te+'" alt="Bilder des Monats"><img src="'+Oe+'" alt="Bilder des Monats"><img src="'+He+'" alt="Bilder des Monats"><img src="'+Pe+'" alt="Bilder des Monats"><img src="'+We+'" alt="Bilder des Monats"><img src="'+Ce+'" alt="Bilder des Monats"><img src="'+Fe+'" alt="Bilder des Monats"><img src="'+Le+'" alt="Bilder des Monats"><img src="'+Ne+'" alt="Bilder des Monats"><img src="'+Re+'" alt="Bilder des Monats"></p>',52),Ke=[Ge];function Ue(qe,Xe){return t(),i("div",null,Ke)}var Ie=e(Qe,[["render",Ue],["__file","2026-05-30-Bilder-Des-Monats-Mai.html.vue"]]);export{Ie as default};
